import { readFile, writeFile } from 'node:fs/promises'
import { resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

import * as tokens from '../src/index.js'

const root = resolve(fileURLToPath(new URL('..', import.meta.url)))
const outputPath = resolve(root, 'docs/GENERATED_REFERENCE.md')
const check = process.argv.includes('--check')

const packageJson = JSON.parse(await readFile(resolve(root, 'package.json'), 'utf8'))
const css = await readFile(resolve(root, 'css/tokens.css'), 'utf8')
const animationCss = await readFile(resolve(root, 'css/animations.css'), 'utf8')

const escapeCell = (value) => String(value).replaceAll('|', '\\|').replaceAll('\n', ' ')

const exportRows = Object.entries(tokens)
  .sort(([left], [right]) => left.localeCompare(right))
  .map(([name, value]) => {
    const kind = Array.isArray(value) ? 'array' : typeof value
    const members = value && typeof value === 'object'
      ? Object.keys(value).sort().map(escapeCell).join(', ')
      : escapeCell(value)
    return `| \`${name}\` | ${kind} | ${members || '-'} |`
  })

const cssRows = [...css.matchAll(/^\s*(--flyto-[\w-]+):\s*([^;]+);/gm)]
  .map(([, name, value]) => [name, value.trim()])
  .sort(([left], [right]) => left.localeCompare(right))
  .map(([name, value]) => `| \`${name}\` | \`${escapeCell(value)}\` |`)

const keyframes = [...animationCss.matchAll(/@keyframes\s+([\w-]+)/g)]
  .map(([, name]) => name)
  .sort()

const entryRows = Object.entries(packageJson.exports)
  .sort(([left], [right]) => left.localeCompare(right))
  .map(([name, target]) => {
    const rendered = typeof target === 'string'
      ? target
      : Object.entries(target).map(([condition, path]) => `${condition}: ${path}`).join('; ')
    return `| \`${name}\` | \`${escapeCell(rendered)}\` |`
  })

const output = `<!-- Generated by scripts/generate-reference.mjs; do not edit. -->

# Flyto2 Design Tokens Generated Reference

This inventory is generated from the package manifest and runtime source. It
contains ${entryRows.length} package entry points, ${exportRows.length} JavaScript exports,
${cssRows.length} CSS custom properties, and ${keyframes.length} CSS keyframes.

## Package Entry Points

| Import | Target |
|---|---|
${entryRows.join('\n')}

## JavaScript Exports

The member column lists keys for objects and arrays, and the literal value for
scalar exports. TypeScript declarations are maintained in \`src/index.d.ts\`.

| Export | Runtime kind | Members or value |
|---|---|---|
${exportRows.join('\n')}

## CSS Custom Properties

| Property | Canonical value |
|---|---|
${cssRows.join('\n')}

## CSS Keyframes

${keyframes.map((name) => `- \`${name}\``).join('\n')}
`

if (check) {
  let current = ''
  try {
    current = await readFile(outputPath, 'utf8')
  } catch {
    // A missing generated file is reported as drift below.
  }
  if (current !== output) {
    process.stderr.write('generated token reference is stale; run npm run docs:generate\n')
    process.exitCode = 1
  } else {
    process.stdout.write('generated token reference: PASS\n')
  }
} else {
  await writeFile(outputPath, output)
  process.stdout.write(`generated token reference: ${outputPath}\n`)
}
